INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Unified multichannel inbox$q$, $q$Website chat, WhatsApp, Telegram, Instagram, Facebook Messenger, Viber, email and calls in one shared agent inbox.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Proactive chat and visitor monitoring$q$, $q$See what page a visitor is browsing in real time and trigger proactive chat invitations to start conversations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Built-in CRM$q$, $q$Lightweight CRM keeps lead details and full conversation history attached to each contact automatically.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$AI Agent and chatbots$q$, $q$Optional AI Agent add-on and chatbot builder auto-answer common questions and qualify leads outside business hours.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Callback and offline forms$q$, $q$Visitors can request a callback or leave an offline message when no agent is available.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Telephony and video calls$q$, $q$Telephony Plus enables click-to-call, and a separate video call module supports face-to-face support sessions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Chat API and mobile SDK$q$, $q$Enterprise plan exposes a Chat API and mobile SDK for embedding JivoChat inside custom websites and native apps.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Cross-platform apps$q$, $q$Native desktop apps for Windows and macOS plus iOS and Android apps keep agents synced wherever they work.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Generous free plan supports up to 5 agents with no time limit$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$True multichannel inbox covering WhatsApp, Telegram, Instagram and more$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Fast, straightforward widget installation on any website$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Built-in CRM and canned responses reduce the need for extra tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Native mobile and desktop apps keep agents responsive on the go$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$WhatsApp connects via a paid third-party (Twilio-based) module rather than a native integration$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Notification volume can feel excessive without tuning settings$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Advanced features like video calls and the Chat API are locked behind the Enterprise tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Per-agent pricing on annual billing adds up quickly for larger support teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Support response times are reported as inconsistent on lower-tier plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Is JivoChat free to use?$q$, $q$Yes. JivoChat offers a permanent Free plan for up to 5 agents with website chat, callback, offline forms and core social integrations. Paid plans starting around $28/agent/month add automation, CRM and multichannel messaging.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Does JivoChat support WhatsApp?$q$, $q$Yes, WhatsApp is available as an integration on the Professional plan and above, delivered through a paid connector (Twilio or similar) rather than a free native integration.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Who owns JivoChat?$q$, $q$JivoChat was founded by Timur Valishev in 2012 and was acquired by Russian banking group Sberbank in June 2021.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Does JivoChat have a mobile app?$q$, $q$Yes, JivoChat provides native iOS and Android apps in addition to desktop apps for Windows and macOS, all synced in real time.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$What is the JivoChat AI Agent?$q$, $q$The AI Agent is an optional paid add-on that automatically answers common customer questions using JivoChat's chatbot and AI tooling, reducing the load on human agents.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$What are the best JivoChat alternatives?$q$, $q$Common alternatives include Tidio, Tawk.to, LiveChat, Intercom and Zendesk Chat, which compete on similar live chat and multichannel features at varying price points.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Small e-commerce support$q$, $q$Online stores add the JivoChat widget to answer pre-sale questions in real time and recover abandoned carts with proactive invitations.$q$, $q$Small to mid-sized online retailers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Multichannel customer support teams$q$, $q$Support teams consolidate WhatsApp, Instagram and website chat into a single agent inbox to avoid missing messages across channels.$q$, $q$Customer support and success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Lead capture for service businesses$q$, $q$Local service businesses use callback widgets and offline forms to capture leads outside business hours and route them into the built-in CRM.$q$, $q$Service-based SMBs$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Up to 5 agents","Website chat widget","Telegram, Facebook, Instagram, Viber integration","Callback widget","Offline forms","Desktop and mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Basic$q$, $q$$28/agent/month$q$, $q$annual$q$, NULL, $q$["Up to 2 agents","Proactive invitations","Real-time visitor monitoring","Automatic assistant","Anti-spam protection","Built-in CRM"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Professional$q$, $q$$42/agent/month$q$, $q$annual$q$, NULL, $q$["Up to 100 agents","Telephony Plus module","WhatsApp integration","Chatbot integration","Voice messages","Chat rescue"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$Enterprise$q$, $q$$56/agent/month$q$, $q$annual$q$, NULL, $q$["Unlimited agents","Mobile SDK","Chat routing","Video call module","Chat API"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$JivoChat began in 2012 as JivoSite, a website live chat widget built to help small online businesses talk to visitors in real time. Founder Timur Valishev grew it into a broader omnichannel messenger that now pulls together website chat, WhatsApp, Telegram, Instagram, Facebook Messenger, Viber, email and phone calls into one inbox, so a support or sales team never has to jump between separate apps to answer a customer.$q$, $q$The company was acquired by Russian banking group Sberbank in 2021 and now operates with a large team based in Vitoria, Brazil, reflecting its strong adoption among Latin American online retailers alongside its original user base. JivoChat reports over 180,000 active business customers and ships desktop, mobile and browser apps that stay synced in real time.$q$, $q$JivoChat is aimed squarely at small and mid-sized businesses that want proactive, affordable live chat rather than a full enterprise help-desk suite, competing with tools like Tidio, Tawk.to, LiveChat and Intercom on price and ease of setup.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, JivoChat is a website chat widget paired with a shared team inbox: agents see real-time visitor activity, can trigger proactive invitations, and can hand off conversations between departments. A built-in lightweight CRM keeps lead and conversation history attached to each contact, and canned responses plus an automatic assistant with ready-made answers speed up repetitive replies.$q$, $q$Beyond the chat widget, JivoChat layers on multichannel messaging (WhatsApp, Telegram, Instagram, Facebook, Viber), a callback widget, offline contact forms, chatbot building tools, and an optional AI Agent add-on that can auto-answer common customer questions. Higher tiers add a Telephony Plus click-to-call module, video calls, chat routing across departments, a Chat API, and a mobile SDK for embedding chat directly into native iOS/Android apps.$q$, $q$Because everything ships as one connected platform with native desktop, mobile and browser apps, teams can staff a single queue that spans channels rather than juggling separate WhatsApp Business, Instagram DM, and email tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f76f119f-94eb-416d-8b1a-53da64763684', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$JivoChat uses a freemium, per-agent-per-month pricing model. The Free plan covers up to 5 agents with website chat, callback, offline forms and basic social integrations. Paid plans are billed per agent (discounted on annual billing): Basic (~$28/agent/month) adds proactive invitations, visitor monitoring and CRM for up to 2 agents; Professional (~$42/agent/month) unlocks WhatsApp, chatbots and voice messages for up to 100 agents; and Enterprise (~$56/agent/month) adds the mobile SDK, chat routing, video calls and Chat API with unlimited agents.$q$, $q$Several capabilities are sold as optional add-on modules rather than bundled into a tier, including the WhatsApp connector, the AI Assistant, Telephony Plus, and video calls, each priced separately per agent. A 14-day free trial is available on paid plans, letting teams test premium features like automation and multichannel routing before committing to a subscription.$q$]::text[], 2);
