INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Scheduling and dispatching$q$, $q$Drag-and-drop calendar assigns and routes jobs to the right technician and crew in real time.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Quoting and invoicing$q$, $q$Send professional quotes clients can approve online, then convert them directly into invoices with online payment collection.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Client hub portal$q$, $q$Customers can request work, approve quotes, view job history and pay invoices through a self-serve online portal.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Route optimization$q$, $q$Automatically sequences multi-stop routes to reduce drive time between jobs across the day.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Job costing and time tracking$q$, $q$Tracks technician time and expenses per job to reveal true profitability.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Two-way SMS and automated reminders$q$, $q$Sends automatic appointment reminders and lets clients reply directly by text.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$QuickBooks and Xero sync$q$, $q$Keeps invoices, payments and client records synced with existing accounting software.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$AI Receptionist and Marketing Suite$q$, $q$Plus-tier tools that answer inbound calls and run marketing campaigns to fill the job pipeline.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$All-in-one platform covering quoting, scheduling, invoicing and payments for home service trades$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Strong mobile app for field technicians keeps office and crew in sync$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Client hub portal reduces phone-tag with customers over quotes and payments$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Deep QuickBooks and Xero integration simplifies bookkeeping$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$14-day free trial with full feature access and no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Pricing climbs quickly for multi-crew teams once additional users are added$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Higher-value features like job costing and automation require the Grow tier or above$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Plus-tier pricing and AI Receptionist put it out of reach for very small solo operators$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Reporting depth is more limited than enterprise tools like ServiceTitan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Some advanced customization requires contacting support rather than self-serve configuration$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$What is Jobber used for?$q$, $q$Jobber is field service management software used by home service businesses (plumbing, HVAC, landscaping, cleaning, electrical, etc.) to schedule jobs, send quotes and invoices, collect payments and manage client relationships.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$How much does Jobber cost?$q$, $q$Jobber's plans start around $21/month for the single-user Core plan and scale up to roughly $280-$420/month for the multi-user Plus plan, with additional users priced separately.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Does Jobber have a free trial?$q$, $q$Yes, Jobber offers a 14-day free trial with full access to Grow-plan features and no credit card required.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Who founded Jobber?$q$, $q$Jobber was founded in 2011 in Edmonton, Alberta, Canada by Sam Pillar and Forrest Zeisler.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Does Jobber integrate with QuickBooks?$q$, $q$Yes, Jobber syncs invoices, payments and clients with both QuickBooks Online and Xero, along with more than 100 other integrations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$What are alternatives to Jobber?$q$, $q$Common Jobber alternatives include Housecall Pro, ServiceTitan, FieldEdge and Workiz, which serve similar home service and field service use cases.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Solo tradesperson operations$q$, $q$A single-operator plumbing or landscaping business uses Jobber's Core plan to send quotes, schedule jobs and get paid without paperwork.$q$, $q$Solo home service operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Growing multi-crew service companies$q$, $q$A cleaning or HVAC company with several crews uses Grow or Plus to dispatch jobs, track job costing and automate client communication.$q$, $q$Multi-crew home service businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Client self-service and payments$q$, $q$Service businesses use the client hub portal so customers can approve quotes and pay invoices online without calling the office.$q$, $q$Customer-facing service teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Core$q$, $q$$21-$30/month$q$, $q$monthly or annual$q$, NULL, $q$["1 user","Online booking","Professional quotes","Invoicing with online payments","Business website","100+ app integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Connect$q$, $q$$70-$120/month$q$, $q$monthly or annual$q$, NULL, $q$["Up to 5 users","Automated client reminders","Automatic payment collection","Job checklists","QuickBooks Online sync","Time and expense tracking"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Grow$q$, $q$$105-$180/month$q$, $q$monthly or annual$q$, NULL, $q$["Up to 10 users","Customizable visual quotes","Upsell capabilities","Automatic time tracking","Job costing","Two-way SMS","Workflow automations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$Plus$q$, $q$$280-$420/month$q$, $q$monthly or annual$q$, NULL, $q$["5-15 users","Centralized job files and media","Team mentions","Marketing Suite","AI Receptionist","Dedicated onboarding and premium support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jobber was founded in Edmonton, Alberta in 2011 by Sam Pillar and Forrest Zeisler after Pillar's own experience running a painting business exposed how much time home service companies lost to paper quotes, spreadsheets and manual invoicing. The platform grew into an all-in-one operations tool for trades like plumbing, HVAC, landscaping, cleaning and electrical work, covering everything from the first client request to the final paid invoice.$q$, $q$Jobber is a cloud-based SaaS product with a web dashboard for office staff and native mobile apps for field technicians, keeping schedules, client records, and job status synced in real time between the office and the truck. The company has raised over 200 million dollars in funding and now employs more than 1,000 people, serving hundreds of thousands of home service professionals across North America.$q$, $q$The product is squarely aimed at small-to-midsize home service businesses that need scheduling, quoting, invoicing and payments in one system rather than a patchwork of separate tools, and it competes most directly with Housecall Pro and the more enterprise-oriented ServiceTitan.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Jobber's core workflow starts with client and property records, professional quotes that clients can approve online, and drag-and-drop scheduling and dispatching that route jobs to the right technician. Invoicing is built in with online payment collection, and a client hub portal lets customers request service, approve quotes, and pay invoices without a phone call.$q$, $q$Operational features include route optimization for multi-stop days, job checklists, automatic time tracking and job costing to see true profitability per job, two-way SMS for client communication, automated reminders and follow-up sequences, and custom workflow automation rules. Higher tiers add a centralized job file view for larger teams, team mentions for internal collaboration, an AI Receptionist that can field incoming calls, and a Marketing Suite for campaigns.$q$, $q$Jobber connects to more than 100 external tools, most notably QuickBooks Online and Xero for accounting sync, along with Mailchimp, Zapier and various payment processors, letting service businesses keep their existing bookkeeping workflow intact.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jobber offers four tiers priced by feature depth and included user count. Core (about $21-$30/month) is built for solo operators and covers online booking, quoting, invoicing and a business website for one user. Connect (about $70-$120/month) adds automated reminders, automatic payment collection and QuickBooks sync. Grow (about $105-$180/month) adds visual quotes, upselling, automatic time tracking, job costing and workflow automation for up to 10 users, and Plus (about $280-$420/month) targets larger operations with 5-15 users, the Marketing Suite, AI Receptionist and dedicated onboarding.$q$, $q$Pricing varies depending on billing commitment (monthly, one-year commitment, or annual prepaid), and additional users can be added to any plan for roughly $29/month each. Jobber offers a 14-day free trial with full access to Grow-tier functionality and no credit card required, letting prospective customers test scheduling, invoicing and automation before subscribing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c23b8837-4a75-4e45-83cf-8a217ebf06ae', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
