INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Candidate pipeline management$q$, $q$Centralized view of every candidate's status across open requisitions with configurable hiring stages.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$AI Interview Companion$q$, $q$AI-assisted screening and interview support module that helps recruiters evaluate candidates faster.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Recruitment marketing$q$, $q$Career site builder and campaign tools to attract and nurture candidates before they apply.$q$, 2);
