INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Onboarding module$q$, $q$Manages new-hire paperwork, tasks and workflows after an offer is accepted.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Interview scheduling automation$q$, $q$Automates back-and-forth interview scheduling and candidate communication.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Analytics and reporting$q$, $q$Pipeline and hiring funnel dashboards for tracking recruiter and requisition performance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$HRIS and job board integrations$q$, $q$Connects to common HR systems, job boards and background-check vendors used by enterprise teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Highly customizable hiring workflows suited to complex enterprise recruiting processes$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Strong automation for candidate communication and interview scheduling$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Modular pricing lets buyers add only the capabilities they need$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Responsive customer support with fast ticket turnaround, per reviewers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Backed by the broader Employ Inc. ecosystem alongside JazzHR and Lever$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$No published pricing; every deal requires a custom sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Interface and navigation feel dated compared to newer ATS competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Notable learning curve for new users and admins$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Reporting and dashboards are less flexible than some rivals$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Better suited to mid-market/enterprise than very small hiring teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$What is Jobvite used for?$q$, $q$Jobvite is an applicant tracking system used by talent acquisition teams to source candidates, manage hiring pipelines, schedule interviews and handle offers and onboarding.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$How much does Jobvite cost?$q$, $q$Jobvite does not publish set pricing. Cost is custom-quoted based on company size and which modules (Onboarding, AI Interview Companion, Recruitment Marketing, etc.) are added to the core ATS.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Is Jobvite the same company as Employ Inc.?$q$, $q$Jobvite is now a brand owned by Employ, Inc., a parent company formed in 2022 after Jobvite merged with JazzHR and NXTThing RPO under private equity owner K1 Investment Management; Employ also owns Lever.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Who founded Jobvite?$q$, $q$Jobvite was founded in 2003 as ForumJobs, Inc. by Jesper Schultz and Hans Larsen, and was renamed Jobvite in 2006.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Where is Jobvite headquartered?$q$, $q$Jobvite's corporate headquarters moved from San Mateo, California to Indianapolis, Indiana in 2021.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$What are alternatives to Jobvite?$q$, $q$Common alternatives include Greenhouse, Lever, iCIMS, SmartRecruiters and JazzHR, several of which compete directly with or sit alongside Jobvite under the Employ Inc. group.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Enterprise high-volume hiring$q$, $q$Large organizations use Jobvite's configurable pipelines and automation to manage high candidate volumes across many open requisitions.$q$, $q$Enterprise talent acquisition teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Employee referral programs$q$, $q$Companies use the Advanced Employee Referrals module to turn staff networks into a structured, incentivized sourcing channel.$q$, $q$HR and recruiting operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$AI-assisted candidate screening$q$, $q$Recruiters use the AI Interview Companion to speed up initial screening and standardize interview evaluation.$q$, $q$Recruiters and hiring managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Jobvite ATS (Core)$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Candidate pipeline management","Requisition management","Interview scheduling","Offer management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Jobvite + Recruitment Marketing$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Everything in Core","Career site and campaign tools","Advanced employee referrals","Candidate nurture"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$Jobvite Enterprise (Employ Suite)$q$, $q$Custom pricing$q$, $q$annual contract$q$, NULL, $q$["Everything in Recruitment Marketing","AI Interview Companion","Onboarding module","Advanced analytics","Access to Employ Inc. ecosystem"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jobvite began in 2003 as ForumJobs, Inc., founded by Jesper Schultz and Hans Larsen, before rebranding as Jobvite in 2006 with a focus on social and referral-based recruiting. Over two decades it grew into a full applicant tracking system used by mid-market and enterprise talent acquisition teams to manage the entire hiring pipeline from sourcing through offer.$q$, $q$The company moved its headquarters from San Mateo, California to Indianapolis, Indiana in 2021, around the same time private equity firm K1 Investment Management merged Jobvite with JazzHR and NXTThing RPO. In 2022 the combined organization was rebranded Employ, Inc., which went on to acquire ATS rival Lever later that year, making Jobvite one of several sibling recruiting brands under the Employ umbrella.$q$, $q$Jobvite today is positioned as Employ's enterprise-tier ATS, aimed at organizations that need a highly configurable hiring workflow with add-on modules for AI screening, onboarding and recruitment marketing.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At its core, Jobvite provides candidate pipeline management, requisition and job posting management, structured interview scheduling, and offer management, all built around a customizable hiring workflow. Teams can automate repetitive steps like candidate communication and interview scheduling, which reviewers consistently point to as a strength.$q$, $q$Beyond the core ATS, Jobvite is sold as a modular platform: customers can add an AI Interview Companion for candidate screening and support, Onboarding tools to manage new-hire paperwork and tasks, Advanced Employee Referrals to turn staff into a sourcing channel, Recruitment Marketing tools for career sites and campaigns, and Analytics dashboards for pipeline reporting.$q$, $q$The platform integrates with common HRIS systems, job boards, background-check vendors and calendaring tools, letting enterprise recruiting teams plug Jobvite into their existing HR technology stack.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jobvite does not publish standard pricing tiers. Instead, the company uses a modular, quote-based pricing model: organizations start with the core ATS and add modules such as Onboarding, the AI Interview Companion, Advanced Employee Referrals or Recruitment Marketing as needed, with cost scaled to company size and module selection.$q$, $q$Prospective customers request pricing through a 'Get My Quote' form on Jobvite's website or by contacting sales directly, consistent with its positioning as a mid-market to enterprise solution rather than a self-serve, credit-card-signup product.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('06eb9255-8dff-49b4-92cb-b6dfc17d5493', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Single-binary self-hosting$q$, $q$Betula runs as one compiled binary with an embedded SQLite database, making self-hosted deployment simple.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Fediverse federation$q$, $q$Public bookmarks can be followed from Mastodon, Akkoma and Smithereen, and Betula instances can follow each other.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Tagging and privacy controls$q$, $q$Bookmarks can be tagged for organization and individually marked public or private.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Page archiving$q$, $q$Optionally saves an archived copy of a bookmarked page so the link stays useful if the source disappears.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Import/export compatibility$q$, $q$Supports Netscape Bookmark File, Pinboard JSON, and Raindrop CSV formats for migrating bookmarks in or out.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$No-JavaScript interface$q$, $q$The web interface is fully usable without JavaScript, keeping the tool lightweight and accessible.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Mycomarkup descriptions$q$, $q$Bookmark notes and descriptions use the lightweight Mycomarkup markup language.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Completely free and open source with no vendor lock-in$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Extremely lightweight single-binary and single-file deployment$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Unique Fediverse-style federation lets public bookmarks be followed like a social feed$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Works without JavaScript, keeping it fast and accessible$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Solid import/export support for migrating from Pinboard, Raindrop or browser bookmarks$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Requires self-hosting and basic server/technical knowledge to run$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Designed for single-user use, not built for team or multi-user bookmarking$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Smaller community and slower feature velocity than commercial alternatives$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$No official hosted/managed version for non-technical users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Documentation and UI polish are less mature than established commercial tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$What is Betula (joinbetula.org)?$q$, $q$Betula is a free, open-source, self-hosted bookmark manager that lets individuals save, tag and optionally share links, with support for Fediverse-style following of public bookmarks.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Is Betula free?$q$, $q$Yes. Betula is free open-source software with no licensing cost; users only pay for whatever server they choose to self-host it on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Do I need technical skills to run Betula?$q$, $q$Some basic comfort with servers is helpful, though Betula is designed to be simple: it is a single binary with an embedded SQLite database and is configured entirely through its web interface.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Can Betula be followed from Mastodon?$q$, $q$Yes. Public bookmarks on a Betula instance can be followed from Fediverse platforms like Mastodon, Akkoma and Smithereen, and Betula instances can follow each other.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Can I import my existing bookmarks into Betula?$q$, $q$Yes, Betula supports importing from the Netscape Bookmark File format, Pinboard's JSON export and Raindrop's CSV export.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$What are alternatives to Betula?$q$, $q$Common alternatives include Linkding, Shaarli, Raindrop.io and Pinboard, though Betula is unique in offering native Fediverse federation for public bookmarks.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Personal self-hosted bookmarking$q$, $q$Individuals who want full control of their saved links deploy Betula on a home server or small VPS instead of using a third-party bookmarking service.$q$, $q$Privacy-conscious individuals and self-hosting enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$IndieWeb and Fediverse linklogs$q$, $q$Fediverse users publish a public linklog that followers on Mastodon or Akkoma can subscribe to directly, similar to following a social account.$q$, $q$IndieWeb and Fediverse community members$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Migrating from commercial bookmark managers$q$, $q$Users leaving Pinboard or Raindrop import their existing bookmark collections into a self-hosted Betula instance to avoid future subscription costs.$q$, $q$Former Pinboard/Raindrop users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Self-Hosted$q$, $q$Free$q$, $q$one-time setup$q$, NULL, $q$["Full feature set","Single binary plus SQLite database","Unlimited bookmarks","Fediverse federation","Import/export tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$Support the Project$q$, $q$Pay what you want$q$, $q$optional donation$q$, NULL, $q$["Voluntary donations to the maintainer","Backed by NLnet Open Social Fund grant","No functional difference from the free self-hosted version"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Betula is a free, open-source, self-hosted bookmark manager created by a developer known as Bouncepaw, who began building it in late 2022 with support from NLnet's Open Social Fund. Rather than relying on a hosted bookmarking service, Betula is designed to be run by individuals on their own server, giving them full ownership of their saved links.$q$, $q$The software is intentionally minimal: it ships as a single compiled binary backed by one SQLite file, and every setting is configured through its own web UI rather than separate config files or a database server. That simplicity makes it fast to deploy on a home server, small VPS, or Raspberry Pi.$q$, $q$What sets Betula apart from most bookmark managers is its Fediverse integration: public bookmarks can be followed from Mastodon, Akkoma or Smithereen much like a social media account, and Betula instances can follow each other, forming a decentralized network of personal linklogs rather than a single centralized bookmarking platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality covers saving bookmarks with titles and Mycomarkup-formatted descriptions, tagging for organization, and marking each bookmark public or private for selective sharing. Betula can also create archived copies of saved pages so links remain usable even if the source page later goes offline.$q$, $q$Import and export support a smooth migration path, with compatibility for the Netscape Bookmark File format, Pinboard's JSON export and Raindrop's CSV export. The interface produces IndieWeb-friendly microformat markup and works without requiring JavaScript, keeping the tool accessible and lightweight.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Betula itself carries no license fee or subscription cost: it is free software that anyone can download, self-host and modify. The only ongoing cost is whatever server or hosting environment a user chooses to run it on, which can range from a free home server to a few dollars a month on a small VPS.$q$, $q$Because there is no company selling Betula as a hosted product, development is sustained through NLnet grant funding and voluntary donations to the maintainer rather than a formal pricing tier structure.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7b5ab72f-cd65-4878-a433-6f7658fc65a4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Native multilingual content$q$, $q$Built-in multilingual content management without requiring a separate translation plugin.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Role-based access control$q$, $q$Granular user groups and permissions let admins control exactly what different users can view or edit.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Extension ecosystem$q$, $q$Over 10,000 templates, plugins, modules and components available through the Joomla Extensions Directory.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$SEO-friendly architecture$q$, $q$Built-in friendly URLs, metadata fields and sitemap support for search engine visibility.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Responsive templating$q$, $q$Modern templates render responsively across desktop and mobile out of the box.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Web Services API$q$, $q$REST-style API enables headless or decoupled front-end architectures.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Media manager$q$, $q$Built-in tools for organizing and inserting images and files across the site.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Community-driven security updates$q$, $q$Regular security and maintenance releases (e.g. Joomla 6.1.2) maintained by the volunteer core team.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Strong native multilingual and access-control features rarely built into competitors by default$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Large extension ecosystem covering e-commerce, forums and more$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Backed by a stable, long-running nonprofit (Open Source Matters) rather than a single company$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Flexible enough for everything from simple blogs to complex membership sites$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Steeper learning curve than WordPress for first-time website builders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Smaller plugin and theme marketplace than WordPress$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Requires self-managed hosting, updates and security patching (or a managed Joomla host)$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Smaller talent pool of developers/agencies compared to WordPress$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Some extensions and premium templates carry separate third-party costs$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Is Joomla free to use?$q$, $q$Yes, Joomla! is free, open-source software released under the GNU General Public License. Costs only arise from hosting, premium extensions or professional services.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Who created Joomla?$q$, $q$Joomla was created in 2005 by the former core development team of the Mambo CMS, including Andrew Eddie, Brian Teeman and Johan Janssens, who founded the nonprofit Open Source Matters, Inc. to govern the new project.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Is Joomla better than WordPress?$q$, $q$Neither is strictly better; Joomla offers stronger built-in multilingual support and access control out of the box, while WordPress has a larger plugin ecosystem and a gentler learning curve for beginners.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$What is the current version of Joomla?$q$, $q$Joomla 6 is the current major release as of 2026, with the project actively maintaining it through regular security and maintenance updates.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Do I need coding skills to use Joomla?$q$, $q$Basic sites can be built without coding using templates and extensions, but Joomla's deeper customization and access-control features typically benefit from some development or configuration experience.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$What are alternatives to Joomla?$q$, $q$The main alternatives are WordPress and Drupal among open-source CMS platforms, and hosted website builders like Wix and Squarespace for users who don't want to self-host.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Multilingual organizational websites$q$, $q$Nonprofits and government agencies use Joomla's native multilingual support to publish content in multiple languages without extra plugins.$q$, $q$Nonprofits, government agencies, NGOs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Membership and access-controlled sites$q$, $q$Organizations use Joomla's role-based access control to restrict content to specific member groups or subscription tiers.$q$, $q$Membership organizations, associations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Agency-built custom web applications$q$, $q$Web development agencies extend Joomla's core with custom components to build tailored web applications for clients.$q$, $q$Web development agencies and freelance developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Joomla! Core (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full open-source CMS","Unlimited websites","Native multilingual support","Role-based access control","Community support and documentation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$Extensions and Templates (Third-Party)$q$, $q$Varies by developer$q$, $q$one-time or subscription$q$, NULL, $q$["Premium templates from the Joomla Extensions Directory","Paid components for e-commerce, forums and more","Optional professional support from extension developers"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Joomla! originated in 2005 as a fork of the Mambo CMS, after most of Mambo's volunteer developers, including Andrew Eddie, Brian Teeman and Johan Janssens, split from Mambo's commercial sponsor over control of the project. They incorporated the nonprofit Open Source Matters, Inc. in New York to steward the new project, and Joomla 1.0 launched on September 16, 2005.$q$, $q$Two decades later, Joomla remains entirely community-developed, with the project reporting more than 1,500 active volunteer contributors, over 155 million downloads, and more than 2 million websites currently running on it worldwide, translated into 76 languages.$q$, $q$Joomla is a PHP and MySQL-based CMS with an extensible architecture of templates, modules, plugins and components, giving developers a foundation to build anything from a simple blog to a complex, access-controlled membership site.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Joomla ships with capabilities that many competing CMS platforms only offer through third-party plugins, most notably native multilingual content management and a granular, role-based access control system for managing what different user groups can view or edit. Its templating system supports responsive, mobile-friendly designs out of the box.$q$, $q$SEO controls are built into the core, including friendly URL structures and metadata fields, and the platform includes a Web Services API for building headless or decoupled front ends. A library of more than 10,000 third-party extensions and templates, distributed through the Joomla Extensions Directory, extends the core with e-commerce, forums, event calendars and other functionality.$q$, $q$Because the software is open source, developers and agencies can modify Joomla's core code directly, which appeals to organizations with custom structural or compliance requirements that off-the-shelf plugins can't fully satisfy.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Joomla! itself is free, released under the GNU General Public License, with no license fee, usage cap or vendor subscription. Anyone can download, self-host and modify the software at no cost.$q$, $q$Real-world costs come from elements outside the core software: web hosting (shared, VPS or managed Joomla hosting), premium templates or extensions sold by third-party developers in the Joomla ecosystem, and any professional design or development services a site owner chooses to hire to build or maintain the site.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b17cb33e-88ec-4a90-a49e-1ba15fca71cb', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Markdown notes with live preview$q$, $q$Notes are written in plain markdown text with a live rendered preview pane.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$End-to-end encryption$q$, $q$Notes can be encrypted client-side before syncing, so even the sync backend cannot read note content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Backend-agnostic sync$q$, $q$Sync via Joplin Cloud, Nextcloud, Dropbox, OneDrive, WebDAV, S3 or a self-hosted Joplin Server.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$To-do lists and reminders$q$, $q$Notes can be checklists with checkboxes and optional reminder notifications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Plugin system$q$, $q$Community-built plugins extend the editor, themes and functionality of the desktop app.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Web clippers$q$, $q$Browser extensions for Chrome and Firefox save articles and pages directly into Joplin.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Full-text search$q$, $q$Searches across all notes, notebooks and attachments instantly.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Cross-platform native apps$q$, $q$Dedicated apps for Windows, macOS, Linux, Android, iOS and a terminal client.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Fully free and open source with no feature paywall on the core apps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$True end-to-end encryption available regardless of sync backend$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$No vendor lock-in: notes are plain markdown, exportable at any time$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Choice of sync backend, including self-hosted options at no cost$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Active plugin ecosystem for extending functionality$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Interface and collaboration features feel less polished than commercial tools like Notion$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Small core team means slower feature development than VC-funded competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Real-time collaborative editing is limited compared to Notion or Google Docs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Self-hosted sync setup requires technical comfort for non-Joplin-Cloud users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Mobile app UX lags behind some native mobile-first note apps$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Is Joplin really free?$q$, $q$Yes, the Joplin apps for desktop, mobile and terminal are free and open source with no feature restrictions. Only the optional managed Joplin Cloud sync service is paid, starting at EUR2.99/month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Who created Joplin?$q$, $q$Joplin was created by developer Laurent Cozic, who began building it in 2016 and released the first versions in 2017.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Does Joplin encrypt my notes?$q$, $q$Yes, Joplin supports end-to-end encryption on synced data, so notes can be encrypted on-device before syncing to any backend, including Joplin Cloud or third-party storage.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Can I self-host Joplin sync?$q$, $q$Yes, Joplin supports self-hosted sync via a self-hosted Joplin Server, as well as Nextcloud, WebDAV, Dropbox, OneDrive and S3, at no cost beyond your own infrastructure.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$What is Joplin Cloud?$q$, $q$Joplin Cloud is the project's optional managed hosting and sync service, launched in 2021, offering paid tiers from Basic (EUR2.99/month) up to Teams (EUR7.99/month per user) for users who don't want to manage their own sync backend.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$What are alternatives to Joplin?$q$, $q$Common alternatives include Evernote, Notion, Obsidian and Standard Notes, though Joplin is distinguished by being fully open source with true end-to-end encryption and no proprietary file format.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Privacy-focused personal note-taking$q$, $q$Individuals who want encrypted, exportable notes use Joplin instead of closed commercial note apps to avoid vendor lock-in.$q$, $q$Privacy-conscious individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Developer and technical documentation$q$, $q$Developers use Joplin's markdown-native notes, plugin system and API to maintain technical notes and documentation.$q$, $q$Developers and technical writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Self-hosted team knowledge base$q$, $q$Small teams deploy a self-hosted Joplin Server or Joplin Cloud Teams plan to share and collaborate on notes while keeping control of their data.$q$, $q$Small teams and open-source organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Free (App)$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Full desktop, mobile and terminal apps","Markdown notes and to-dos","End-to-end encryption","Free sync via Dropbox, OneDrive, Nextcloud, WebDAV or S3"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Joplin Cloud Basic$q$, $q$EUR2.99/month$q$, $q$monthly (EUR2.40/month yearly)$q$, NULL, $q$["2GB storage","10MB per note/attachment","Managed sync","Publish notes","Read-only collaboration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Joplin Cloud Pro$q$, $q$EUR5.99/month$q$, $q$monthly (EUR4.79/month yearly)$q$, NULL, $q$["30GB storage","200MB per note/attachment","Share notebooks","Email-to-note","Customizable publishing"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$Joplin Cloud Teams$q$, $q$EUR7.99/month per user$q$, $q$monthly (EUR6.69/month yearly), minimum 2 users$q$, NULL, $q$["50GB storage per user","Multi-user management","Consolidated billing","Share permissions"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Joplin was started in 2016 by developer Laurent Cozic, who wanted a note-taking app that stored data in an open, exportable format rather than locking notes inside a proprietary commercial service like Evernote. The first CLI version shipped in mid-2017, quickly followed by Android, desktop and browser clipper releases, and the app was named after ragtime composer Scott Joplin.$q$, $q$As an open-source, non-profit-oriented project, Joplin has no venture funding; it is sustained by user donations, a small core team of a few regular contributors led by Cozic, and revenue from the optional paid Joplin Cloud sync service, which operates as a registered business in France and launched in 2021 alongside a self-hostable Joplin Server option.$q$, $q$The apps and sync protocol are designed around markdown notes, full data portability, and true end-to-end encryption, making Joplin a favorite among privacy-conscious users and developers who don't want to be locked into a single vendor's ecosystem.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Joplin notes are written in markdown with live preview, organized into notebooks and tags, and support to-do items with checkboxes and reminders, file and image attachments, and full-text search across the entire note collection. Native apps exist for Windows, macOS, Linux, Android and iOS, along with a terminal client and Chrome/Firefox web clippers for saving content from the browser.$q$, $q$A plugin system lets the community extend Joplin's functionality much like editor extensions, and a public API supports custom integrations and automation. Most importantly, Joplin supports end-to-end encryption on synced data, meaning notes can be encrypted before they ever leave the device, regardless of which sync backend is used.$q$, $q$Sync is backend-agnostic: users can choose Joplin Cloud, Nextcloud, Dropbox, OneDrive, WebDAV, Amazon S3, or a self-hosted Joplin Server, giving privacy-conscious users full control over where their data physically lives.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4de112c5-5df2-4ef8-9c42-0ec1c3bde762', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core Joplin apps are free and open source forever, with no feature gating, and users can sync for free using their own Dropbox, OneDrive, Nextcloud, WebDAV or S3 account, or a self-hosted Joplin Server. This makes Joplin fully usable at zero cost for technically comfortable users.$q$, $q$For users who want managed sync without setting up their own backend, Joplin Cloud offers paid tiers: Basic at EUR2.99/month (2GB storage), Pro at EUR5.99/month (30GB storage plus sharing and email-to-note), a 100GB Pro tier at EUR9.99/month, and Teams at EUR7.99/month per user for multi-user collaboration with consolidated billing. A custom-quoted Joplin Server Business plan supports self-hosted, unlimited-storage team deployments.$q$]::text[], 2);
