INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Jotform AI Agents$q$, $q$Deploys a conversational AI agent on a website to collect information or answer questions interactively.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Report Builder$q$, $q$Turns raw submission data into shareable dashboards and business reports.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$HIPAA-compliant forms$q$, $q$Gold and Enterprise plans support HIPAA-compliant data collection for healthcare use cases.$q$, 7);
