INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Bootstrapped, profitable company with a long track record of stability$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Strong integration ecosystem with Google Sheets, Salesforce, Airtable and payment processors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Pricing tiers are gated by submission volume, which can force upgrades faster than expected for growing teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Interface can feel cluttered given the breadth of bundled products$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Free and lower tiers carry Jotform branding on forms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$HIPAA compliance requires the more expensive Gold or Enterprise tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$AI Agent conversation limits add another usage dimension to track alongside submissions$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Is Jotform free?$q$, $q$Yes, Jotform's Starter plan is free forever, with 5 active forms, 100 monthly submissions and 100MB of storage, though forms carry Jotform branding on the free tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Who founded Jotform?$q$, $q$Jotform was founded in 2006 by Aytekin Tank, who bootstrapped the company without outside venture funding.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$How much does Jotform cost?$q$, $q$Paid plans start around $39/month for Bronze and scale up to $129/month for Gold, with custom Enterprise pricing for organizations needing unlimited usage and SSO.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Does Jotform support payments?$q$, $q$Yes, Jotform integrates with more than 30 payment gateways including Stripe, PayPal and Square, letting forms collect payments directly.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$What is the difference between Jotform and Jotform Sign?$q$, $q$Jotform is the core form-building platform; Jotform Sign is a dedicated e-signature product built by Jotform that can be used standalone or combined with Jotform forms and workflows.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$What are alternatives to Jotform?$q$, $q$Common alternatives include Google Forms, Typeform, Microsoft Forms, Wufoo and Formstack, though Jotform offers a broader bundled feature set across payments, e-signatures and workflows.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Lead capture and contact forms$q$, $q$Small businesses embed Jotform forms on their website to capture leads and route submissions to email or a CRM.$q$, $q$Small businesses and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Order forms with payment collection$q$, $q$Merchants build order forms that collect payment directly via Stripe or PayPal integration without a full e-commerce site.$q$, $q$Merchants and service providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$HR and operations approval workflows$q$, $q$Enterprise teams use Jotform Approvals and Tables to route submissions like expense requests or time-off through multi-step approval chains.$q$, $q$HR and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Starter$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["5 active forms","100 monthly submissions","100MB upload space","5 AI Agents","Jotform branding"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Bronze$q$, $q$$39/month$q$, $q$monthly ($34/month billed annually)$q$, NULL, $q$["25 active forms","1,000 monthly submissions","1GB upload space","Removable branding","25 AI Agents"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Silver$q$, $q$$49/month$q$, $q$monthly ($39/month billed annually)$q$, NULL, $q$["50 active forms","2,500 monthly submissions","10GB upload space","Removable branding","50 AI Agents"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$Gold$q$, $q$$129/month$q$, $q$monthly ($99/month billed annually)$q$, NULL, $q$["100 active forms","10,000 monthly submissions","100GB upload space","HIPAA support","100 AI Agents"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jotform was founded in 2006 by Aytekin Tank, who built and grew the company entirely without outside venture funding, a distinctive path for a SaaS company of its current scale. Headquartered in San Francisco with additional offices in Turkey, the UK, Canada and Australia, Jotform now serves more than 25 million users and employs roughly 900 people worldwide.$q$, $q$The product is a cloud-based drag-and-drop form builder, accessible via web app and native iOS/Android apps, that lets anyone create web forms, surveys and workflows without code, then embed them on any website or share them via link.$q$, $q$Over time Jotform expanded well beyond simple forms into a broader productivity suite: it now bundles e-signature collection, payment processing, spreadsheet-style data tables, report building, approval workflows and conversational AI agents into the same platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core is the Form Builder, a drag-and-drop editor with more than 10,000 templates and conditional logic that shows or hides fields based on prior answers. Forms can collect e-signatures through Jotform Sign, accept payments via more than 30 gateway integrations including Stripe, PayPal and Square, and feed directly into Jotform Tables for spreadsheet-style management of submission data.$q$, $q$Jotform Report Builder turns submission data into shareable dashboards and reports, while Jotform Approvals lets teams build multi-step approval workflows triggered by form submissions, useful for HR, procurement and operations processes. The newer Jotform AI Agents feature lets businesses deploy a conversational AI assistant on their website to collect information interactively instead of, or alongside, a static form.$q$, $q$Because these tools are bundled into one platform rather than sold as separate products, teams can go from data collection to payment to approval to reporting without leaving Jotform or stitching together multiple vendors.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bd5a4743-03ea-4f41-9507-17a3a9f17894', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jotform's pricing is freemium and usage-based, gated mainly by monthly submissions, active forms, storage and AI Agent conversations rather than by locking away entire feature categories. The free Starter plan supports 5 forms and 100 submissions/month with Jotform branding, making it usable indefinitely for light needs.$q$, $q$Paid tiers scale usage limits and remove branding: Bronze (~$39/month) supports 25 forms and 1,000 submissions; Silver (~$49/month) supports 50 forms and 2,500 submissions with 10GB storage; and Gold (~$129/month) supports 100 forms, 10,000 submissions, 100GB storage and HIPAA-compliance support. Enterprise pricing is custom for organizations that need unlimited usage, SSO and dedicated support, and all paid plans are discounted roughly 15-25 percent when billed annually.$q$]::text[], 2);
