INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$1,000+ signable templates$q$, $q$Ready-made templates for contracts, waivers, consent forms, NDAs and other common documents.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Multi-channel sharing$q$, $q$Documents can be sent via email, shareable link, or embedded directly on a website.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Multi-step approval flows$q$, $q$Routes a document through several signers or approvers in a defined sequence.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Sign Inbox and reminders$q$, $q$Centralized inbox with instant notifications and automated reminder emails for pending signatures.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Jotform Tables integration$q$, $q$Signed document data flows automatically into Jotform Tables for spreadsheet-style tracking.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Mobile signing$q$, $q$Signers can complete documents from any device via Jotform's mobile apps or a browser.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Report Builder integration$q$, $q$Turns signature and document completion data into shareable business reports.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Free to use, bundled into existing Jotform account plans rather than a separate subscription$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Large library of 1,000+ signable document templates$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Deep integration with Jotform Tables, Report Builder and forms$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Multi-step approval routing for sequential signers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Mobile-friendly signing experience for on-the-go signers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Less specialized than dedicated e-signature vendors like DocuSign or PandaDoc$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$No standalone pricing page, so document limits are tied to a Jotform account plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$HIPAA-compliant signing requires upgrading to Jotform's Gold or Enterprise tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Smaller enterprise contract-management feature set than pure-play competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Brand recognition in e-signature is lower than established leaders like DocuSign$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Is Jotform Sign free?$q$, $q$Yes, Jotform Sign is free to use and is bundled into Jotform's existing account plans rather than sold as a separate paid product.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$When did Jotform Sign launch?$q$, $q$Jotform Sign launched publicly in October 2022 as an e-signature extension of Jotform's form-building platform.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Is Jotform Sign legally binding?$q$, $q$Yes, Jotform Sign is designed to collect legally binding electronic signatures on contracts, waivers, consent forms and other documents.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Can I convert a PDF into a signable document?$q$, $q$Yes, Jotform Sign lets users convert existing PDF documents into fillable, signable documents with a single click.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Does Jotform Sign support multiple signers?$q$, $q$Yes, Jotform Sign supports multi-step approval flows that route a document through several signers or approvers in sequence.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$What are alternatives to Jotform Sign?$q$, $q$Common alternatives include DocuSign, Adobe Acrobat Sign, PandaDoc, HelloSign (Dropbox Sign) and SignNow.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Contract and NDA signing$q$, $q$Businesses send contracts and NDAs built from templates and track signature status through the Sign Inbox.$q$, $q$Small businesses and legal/operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$HR onboarding paperwork$q$, $q$HR teams route offer letters and onboarding documents through multi-step approval flows for sequential signing.$q$, $q$HR teams$q$, 1);
