INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Starter$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Included with free Jotform account","Basic signable documents","PDF-to-signable conversion","Template library access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Bronze$q$, $q$$39/month (Jotform plan)$q$, $q$monthly ($34/month billed annually)$q$, NULL, $q$["Higher document volume","Removable branding","Sign Inbox with reminders"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Silver$q$, $q$$49/month (Jotform plan)$q$, $q$monthly ($39/month billed annually)$q$, NULL, $q$["Increased document and storage limits","Multi-step approval flows","Jotform Tables integration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$Gold / Enterprise$q$, $q$$129/month or custom (Jotform plan)$q$, $q$monthly ($99/month billed annually) or custom annual$q$, NULL, $q$["HIPAA-compliant signing","Highest document volume","Dedicated support (Enterprise)","SSO and data residency (Enterprise)"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Jotform Sign is the e-signature product built by Jotform, launched publicly in October 2022 as an extension of Jotform's existing form-building platform. Rather than being a separately funded startup, it shares Jotform's San Francisco headquarters, roughly 900-person team, and bootstrapped business model, and was built specifically so Jotform customers could collect legally binding signatures without adopting a separate e-signature vendor.$q$, $q$The product lets users turn existing PDFs into signable documents with one click, or start from more than 1,000 templates covering contracts, waivers, consent forms and NDAs. Documents can be shared by email, link, or website embed, and signed from any device through Jotform's apps.$q$, $q$Because Jotform Sign is bundled into the broader Jotform ecosystem, signed document data flows directly into Jotform Tables and Report Builder, letting teams manage and report on signature data the same way they manage form submission data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes one-click PDF-to-signable-document conversion, a library of 1,000+ ready-made templates, and multiple sharing methods (email, link, website embed) for collecting signatures. A Sign Inbox gives senders real-time notifications and automated reminder emails so pending signatures don't get lost.$q$, $q$Automation features include multi-step approval flows that route a document through several signers or approvers in sequence, and completed documents can be automatically archived and synced to connected cloud storage. Signature and document data can also feed directly into Jotform Tables and Report Builder for downstream tracking and reporting.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6897dd1f-98ec-4f63-aeb4-0b690c857608', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Jotform Sign does not have a separate standalone pricing page; it is offered free to use and included within Jotform's existing account plans, from the free Starter tier through Bronze, Silver, Gold and custom Enterprise tiers. Document and usage limits scale with whichever Jotform plan the account is on, the same way form submission limits do.$q$, $q$Organizations that need HIPAA-compliant document handling for signatures, common in healthcare intake and consent workflows, need to be on Jotform's Gold plan or above, or a custom Enterprise agreement, mirroring the compliance gating on Jotform's core form product.$q$]::text[], 2);
