-- Enrichment marathon batch: JivoChat, Jobber, Jobvite, Betula, Joomla!, Joplin, Jotform, Jotform Sign

-- ── JivoChat ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$JivoChat is an omnichannel business messenger unifying website chat, WhatsApp, Telegram, Instagram, and email in one shared inbox.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $28/agent/month)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Vitoria, Brazil$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Portuguese$q$, $q$Spanish$q$, $q$Russian$q$]::text[],
  seo_title = COALESCE($q$JivoChat Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$JivoChat review: omnichannel live chat, WhatsApp, Telegram and CRM in one inbox. See 2026 pricing tiers, real features, pros, cons and the best alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$JivoChat is an omnichannel business messenger and live chat platform that lets companies talk to website visitors and customers across chat widgets, WhatsApp, Telegram, Instagram, Facebook Messenger, Viber, email and phone calls from a single shared team inbox. The product was created in 2012 by Timur Valishev, who launched the service (originally branded JivoSite) out of Russia to give small and mid-sized online businesses an easy way to add proactive live chat to their websites; it grew into one of the most widely installed live chat widgets globally, with vendor-reported figures citing more than 180,000 active business customers. In June 2021 Russian banking group Sberbank acquired JivoChat for a reported 20.5 million dollars, folding it into Sberbank's broader e-commerce and SME software portfolio. Today the company operates internationally with a significant share of its team based in Vitoria, Brazil, reflecting JivoChat's large footprint in Latin American markets alongside its original CIS user base; some corporate registration records also list a Wilmington, Delaware entity, a common structure for internationally operating SaaS companies. Technically, JivoChat ships as an embeddable JavaScript widget for websites plus native desktop apps (Windows, macOS), mobile apps (iOS, Android), and a browser-based agent console, all synced in real time through JivoChat's own backend so a single agent can answer a chat, WhatsApp message, and email from one screen. Core features include a unified multichannel inbox, canned responses and an automatic assistant with ready-made answers, proactive chat invitations and visitor monitoring that shows what page a visitor is on in real time, a callback widget that lets visitors request a phone call, offline contact forms, a lightweight built-in CRM for tracking leads and conversation history, chatbot building tools, an AI Agent add-on that can auto-answer common questions, chat routing and departments for larger teams, a Telephony Plus module for click-to-call, video calls, and a Chat API and mobile SDK for embedding chat inside native apps. Pricing is freemium: the Free plan supports up to 5 agents with core website chat, callback, offline forms and the major social integrations at no cost. Paid tiers are billed per agent per month (cheaper on annual billing): Basic at roughly 28 dollars/agent/month adds proactive invitations, visitor monitoring, the automatic assistant and CRM for up to 2 agents; Professional at roughly 42 dollars/agent/month unlocks WhatsApp integration, voice messages, chatbots and chat rescue for up to 100 agents; and Enterprise at roughly 56 dollars/agent/month adds the mobile SDK, chat routing, video calls and the Chat API with unlimited agents. Optional add-on modules (WhatsApp connector, AI Assistant, Telephony Plus, video calls, Jivo Marketing) are priced separately, and a 14-day free trial is offered on paid plans. JivoChat targets small and medium-sized e-commerce stores, service businesses, and support teams that want an affordable, quick-to-install alternative to enterprise help-desk suites. It competes directly with Tidio, Tawk.to, LiveChat, Intercom and Zendesk Chat; JivoChat differentiates on its generous free tier, native multichannel messaging (especially WhatsApp and Telegram) bundled into the product, and pricing aimed at cost-conscious SMBs rather than large enterprise support organizations. Reported G2 ratings sit around 4.6 out of 5, with reviewers praising ease of setup and the multichannel inbox, while common complaints cite WhatsApp requiring a paid Twilio-based connector rather than a native integration, occasional notification overload, and slower support response times on lower tiers.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f76f119f-94eb-416d-8b1a-53da64763684';

