-- ── Jobber ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Jobber is field service management software that helps home service businesses schedule, quote, invoice and get paid.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$21/month (Core plan)$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$1,000+ employees$q$, company_size),
  headquarters = COALESCE($q$Edmonton, Alberta, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Jobber Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Jobber review: field service scheduling, quoting, invoicing and payments for home service businesses. See 2026 pricing tiers, pros, cons and alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Jobber is field service management software built for home service businesses such as plumbers, electricians, landscapers, cleaners, HVAC technicians and other on-site trades, covering the full job lifecycle from quoting through scheduling, invoicing and payment collection. The company was founded in 2011 in Edmonton, Alberta, Canada by Sam Pillar and Forrest Zeisler, who started the business after Pillar ran his own painting company and experienced firsthand how much time small service businesses lost to paper-based scheduling and invoicing; Jobber remains headquartered in Edmonton and has grown into one of the largest software employers in Western Canada, with reported headcount exceeding 1,000 employees as of 2026. Jobber has raised more than 200 million dollars in venture funding across multiple rounds from investors including Summit Partners, Version One Ventures and other growth-stage backers, and vendor-reported estimates place its annual recurring revenue above 100 million dollars, serving well over 200,000 home service professionals across North America. Architecturally, Jobber is a cloud-based SaaS platform accessible through a web dashboard and native iOS/Android mobile apps used by field technicians, syncing schedules, client records, and job data in real time between the office and the field; it integrates with more than 100 third-party tools including QuickBooks Online, Xero, Mailchimp and various payment processors. Core functionality spans client and property management, drag-and-drop scheduling and dispatching, route optimization for crews, professional quote and invoice generation with online approval and online payments, a client hub portal where customers can request work and pay invoices, automated appointment reminders and follow-ups, job costing and time tracking, two-way SMS messaging with clients, custom workflow automations, and performance reporting dashboards. Pricing is tiered by feature depth and user count rather than a simple per-seat model: the Core plan (roughly 21 to 30 dollars/month depending on commitment) supports a single user with online booking, quoting, invoicing and a business website; Connect (roughly 70 to 120 dollars/month) adds automated client reminders, automatic payment collection, checklists and QuickBooks sync; Grow (roughly 105 to 180 dollars/month) adds customizable visual quotes, upselling, automatic time tracking, job costing and workflow automation for up to 10 users; and Plus (roughly 280 to 420 dollars/month) is built for larger multi-crew operations with 5 to 15 users, centralized job files, team mentions, an AI Receptionist feature, a Marketing Suite, and dedicated onboarding support. Additional users can be added to any plan for around 29 dollars/month each, and Jobber offers a 14-day free trial with full access to Grow-tier features, no credit card required. Jobber's target audience is small-to-midsize home service companies, typically ranging from solo operators to multi-crew businesses with dozens of technicians, who need an all-in-one operations tool rather than stitching together separate scheduling, invoicing and payment apps. Its main competitors are Housecall Pro, ServiceTitan, FieldEdge and Workiz; Jobber differentiates through a strong reputation for ease of use and customer support, a lower price point than enterprise-focused ServiceTitan, and deep specialization in home services rather than broader field service or asset management use cases.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c23b8837-4a75-4e45-83cf-8a217ebf06ae';

