-- ── Jobvite ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Jobvite is an applicant tracking and recruiting platform, now an Employ Inc. brand, for sourcing, screening and hiring talent.$q$, short_description),
  pricing_model = COALESCE($q$Enterprise$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (contact sales)$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE($q$500+ employees (Employ Inc.)$q$, company_size),
  headquarters = COALESCE($q$Indianapolis, Indiana, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Jobvite Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Jobvite review: applicant tracking, AI screening and recruitment marketing from Employ Inc. See 2026 pricing, features, pros, cons and top alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Jobvite is an applicant tracking system (ATS) and recruiting platform used by talent acquisition teams to source candidates, run structured hiring workflows, screen applicants and manage employee referrals. The company traces back to 2003, when it was founded under the name ForumJobs, Inc. by Jesper Schultz and Hans Larsen; the company rebranded as Jobvite in 2006 and built its early reputation around social recruiting and referral tools before expanding into a full ATS. Jobvite was originally headquartered in San Mateo, California, and relocated its corporate headquarters to Indianapolis, Indiana in 2021. Its ownership structure changed significantly starting in 2019, when private equity firm K1 Investment Management invested more than 200 million dollars in Jobvite, funding acquisitions of Talemetry, RolePoint and Canvas to expand its recruitment marketing and texting capabilities. In April 2021, K1 merged Jobvite with two other portfolio companies, JazzHR and NXTThing RPO, and in 2022 the combined business was rebranded as Employ, Inc., a parent holding company that positions Jobvite as its enterprise-tier ATS brand alongside JazzHR (aimed at small business) and NXTThing (recruitment process outsourcing). Employ, Inc. further expanded in August 2022 by acquiring Lever, another well-known ATS and CRM vendor, making Employ one of the largest talent acquisition software groups by combined customer base. Architecturally, Jobvite is a cloud-based, modular SaaS platform: customers start with the core ATS (candidate pipeline management, requisition management, interview scheduling and offer management) and add modules as needed, including an AI Interview Companion for candidate screening and interview support, Onboarding, Advanced Employee Referrals, Recruitment Marketing (career site and campaign tools), and Analytics and reporting dashboards. It integrates with common HRIS platforms, job boards, background-check vendors and calendar tools used by enterprise recruiting teams. Jobvite does not publish list pricing; instead, prospective customers request a custom quote through a 'Get My Quote' form, with pricing scaled to company size, module selection and contract term, consistent with its positioning as a mid-market to enterprise recruiting solution. G2 reviewers give Jobvite roughly a 4.0 out of 5 rating based on hundreds of reviews, praising its customizable, automatable hiring workflows, candidate communication tools and responsive customer support, while criticizing a dated, sometimes slow interface, a real learning curve for new users, and reporting/dashboard tools that reviewers describe as inflexible compared to newer competitors. Jobvite's target audience is mid-market and enterprise HR and talent acquisition teams that need a configurable ATS with built-in recruitment marketing and referral capabilities rather than a lightweight hiring tool for very small teams. Its primary competitors, several of which are now sibling brands under the same Employ Inc. umbrella, include Greenhouse, Lever, iCIMS, SmartRecruiters and JazzHR; Jobvite differentiates through its long history in social and referral-driven recruiting, its modular add-on approach that lets buyers pay only for the capabilities they need, and its backing by the broader Employ Inc. product and data ecosystem.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '06eb9255-8dff-49b4-92cb-b6dfc17d5493';

