-- ── Betula ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Betula is a free, open-source, self-hosted bookmark manager with optional Fediverse sharing, run as a single binary and SQLite file.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2022, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Betula Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Betula review: a free, self-hosted, federated bookmark manager for the Fediverse. See 2026 features, setup steps, pros, cons, FAQs and open-source alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Betula, published at joinbetula.org, is a free and open-source, self-hosted bookmark and linklog manager built for individuals who want to own and control their personal collection of saved links rather than depending on a commercial bookmarking service. The project is developed primarily by a single maintainer known online as Bouncepaw, who began work on Betula toward the end of 2022 and continues to lead development, with the project receiving funding support from NLnet's Open Social Fund, a grant program that backs decentralized and user-respecting internet software. Betula's source code is hosted on Codeberg (with mirrors on GitHub and SourceHut), and the software is released as free software so anyone can inspect, modify or self-host it without licensing fees. Architecturally, Betula is deliberately minimal: it compiles to a single binary, stores an entire bookmark collection in one SQLite database file, and is configured entirely through its own web interface rather than external config files, which makes deployment on a home server, VPS or Raspberry Pi straightforward. The web interface itself works without JavaScript, keeping the tool lightweight and accessible. Functionally, Betula lets a user save bookmarks with optional titles and descriptions formatted in Mycomarkup (a lightweight markup language used across the Bouncepaw/Mycorrhiza ecosystem of tools), tag bookmarks for organization, and mark individual bookmarks as public or private for selective sharing. A distinguishing feature is Fediverse integration: because Betula speaks ActivityPub-adjacent protocols, other Fediverse users on platforms like Mastodon, Akkoma or Smithereen can follow a person's public Betula feed and receive new bookmarks the way they would follow a social media account, and Betula instances can likewise follow one another to build a decentralized linklog network rather than a centralized bookmarking silo. Betula also supports archiving copies of saved pages so links remain useful even if the original page disappears, and it supports import and export in common formats including the Netscape Bookmark File format, Pinboard's JSON export, and Raindrop's CSV export, easing migration to or from other bookmark managers. Because Betula is entirely self-hosted software with no vendor-run service tier, there is no subscription pricing; the only 'cost' is server hosting (which can be as cheap as a few dollars a month or entirely free on a home server) plus optional voluntary donations to support Bouncepaw's ongoing development work. Betula's target audience is technically comfortable individuals, IndieWeb enthusiasts, and Fediverse users who want a personal, federated alternative to closed bookmarking services and are comfortable running a small self-hosted application. Its closest competitors are Linkding, Shaarli, Raindrop.io and Pinboard; Betula differentiates from all of them through its native Fediverse/ActivityPub-style federation (letting bookmarks be followed like a social feed), its extremely small single-binary footprint, and its IndieWeb-friendly microformat output, though it deliberately targets single-user deployments rather than multi-user team bookmarking.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '7b5ab72f-cd65-4878-a433-6f7658fc65a4';

