-- ── Joomla! ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Joomla! is a free, open-source content management system used to build websites, blogs and online applications.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$German$q$, $q$French$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$Joomla! Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Joomla! review: the free open-source CMS powering millions of sites. See 2026 features, extensions, pricing, pros, cons and WordPress/Drupal alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Joomla! is a free, open-source content management system (CMS) that lets people build websites, blogs, online stores and web applications without writing custom software from scratch. The project originated in August 2005 out of a dispute between the volunteer development team of Mambo, an earlier open-source CMS, and Mambo's commercial sponsor, Miro International, over control of the project's governance and trademark. Most of the core Mambo development team, including Andrew Eddie, Brian Teeman, Johan Janssens and others, resigned and forked the codebase to create a new project; they incorporated a nonprofit organization called Open Source Matters, Inc. in New York State on September 23, 2005, to hold the project's assets and provide legal and organizational backing independent of any single company, and Joomla! 1.0 was released on September 16, 2005. Open Source Matters remains the legal steward of the Joomla trademark and infrastructure today, and Joomla is developed entirely by a global volunteer community, reported by the project at more than 1,500 active contributors, rather than by paid employees of a single vendor. Technically, Joomla is a PHP application backed by a MySQL (or compatible) database, following a Model-View-Controller architecture with an extensible plugin, module, template and component system that lets developers add functionality (e-commerce, forums, event calendars, membership systems) without modifying core code. The current major release is Joomla 6, continuing a long version history that includes the widely used Joomla 3.x and 4.x series; the project reports over 155 million total downloads, more than 2 million live websites currently running Joomla, and a library of more than 10,000 third-party extensions and templates available through the Joomla Extensions Directory, with the core software translated into 76 languages. Core built-in capabilities include a full user and role-based access control system, native multilingual content management without requiring a plugin, SEO-friendly URL structures and metadata controls, responsive templating out of the box, media management, and a REST-style Web Services API for headless or decoupled use cases. Because Joomla is free software released under the GNU General Public License, there is no vendor pricing tier for the software itself; costs to a real deployment come from separately purchased web hosting, premium templates or extensions from third-party developers, and any professional development or design services a site owner chooses to hire. Joomla's target audience spans hobbyist website builders, small businesses, nonprofits, government agencies, and web development agencies that need more built-in structural and access-control flexibility than a blog-first platform typically offers, particularly for multilingual or membership-driven sites. Its primary competitors are WordPress, by far the dominant open-source CMS by market share, along with Drupal, which competes for the same enterprise and complex-site use cases, and hosted website builders like Wix and Squarespace; Joomla differentiates from WordPress through stronger built-in access control and native multilingual support out of the box, and differentiates from Drupal through a comparatively gentler learning curve, while remaining a smaller ecosystem than either in terms of extensions and market share.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b17cb33e-88ec-4a90-a49e-1ba15fca71cb';

