  starting_price = COALESCE($q$Free (app); Joplin Cloud from EUR2.99/month$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$, $q$German$q$, $q$Spanish$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$Joplin Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Joplin review: the free, open-source, end-to-end encrypted note app. See 2026 Joplin Cloud pricing, features, pros, cons and Evernote/Notion alternatives compared.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Joplin is a free and open-source note-taking and to-do application built around markdown notes, end-to-end encryption, and full data portability, created as an alternative to closed commercial note apps like Evernote. Developer Laurent Cozic began building Joplin in 2016 after being frustrated that notes, attachments and tags in mainstream commercial note apps couldn't easily be exported or manipulated by other tools; the first command-line version shipped on July 12, 2017, followed quickly by an Android app on July 28, 2017, and the first public desktop release (version 0.10.19) on November 20, 2017, with browser clipper extensions for Chrome and Firefox following in 2017 and 2018. Joplin has no venture funding and is not a traditional company; it operates as an open-source project sustained through user donations (including Patreon), GitHub Sponsors, and revenue from its optional paid Joplin Cloud service, with a small core team of three to four regular contributors led by Cozic plus periodic student contributors through programs like Google Summer of Code; Joplin Cloud, the project's managed sync and hosting offering introduced in 2021, operates as a registered business entity in France. Architecturally, Joplin stores notes as plain markdown text with a SQLite-backed local database, and ships native apps for Windows, macOS, Linux, Android and iOS, plus a terminal client and browser web clippers, all of which can sync notes end-to-end across devices via several optional backends: Joplin Cloud, Nextcloud, Dropbox, OneDrive, WebDAV, S3, or a self-hosted Joplin Server. All synced data can be end-to-end encrypted client-side, meaning even Joplin's own cloud servers cannot read note content, a key differentiator from most commercial note-taking tools. Feature-wise, Joplin supports markdown formatting with live preview, to-do lists with checkboxes and reminders, tagging and notebooks for organization, file and image attachments, full-text search, a plugin system (introduced to extend functionality similar to VS Code extensions), and a public API for building integrations. Pricing is freemium: the desktop, mobile and terminal apps are entirely free and open source forever, with self-hosted sync options (Nextcloud, WebDAV, Dropbox, S3, self-hosted Joplin Server) costing nothing beyond whatever infrastructure the user already has. For users who want managed, zero-maintenance sync and collaboration, Joplin Cloud offers paid tiers: Basic at EUR2.99/month (EUR2.40/month billed yearly) with 2GB storage; Pro at EUR5.99/month (EUR4.79/month yearly) with 30GB storage plus notebook sharing, email-to-note and customizable publishing; a Pro 100GB tier at EUR9.99/month (EUR7.99/month yearly); and Teams at EUR7.99/month per user (EUR6.69/month yearly, minimum two users) with 50GB storage per user and consolidated team billing and permissions. A custom-quoted Joplin Server Business tier offers self-hosted, unlimited-storage deployment with full collaboration features for organizations that need to keep data entirely on their own infrastructure. Joplin's target audience is privacy-conscious individuals, developers, and open-source advocates who want a note-taking tool free of vendor lock-in, with markdown-native, encryptable, and exportable data. Its main competitors are Evernote, Notion, Obsidian and Standard Notes; Joplin differentiates through being fully open source with no proprietary file format, offering true end-to-end encryption on synced data, and giving users the choice of any sync backend rather than requiring the vendor's own cloud.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4de112c5-5df2-4ef8-9c42-0ec1c3bde762';

